+++ lib/libdisk/create_chunk.c	1996/07/22 13:23:26
@@ -257,6 +257,8 @@
 	bmaj = 0, cmaj = 3;
     else if (!strncmp(p, "sd", 2))
 	bmaj = 4, cmaj = 13;
+    else if (!strncmp(p, "od", 2))
+	bmaj = 20, cmaj = 70;
     else {
 	return 0;
     }
